# Test for main.py::get_user
def test_get_user(client):
    """UNIVERSAL test for maximum coverage."""
    # Create a user
    user_data = {"username": "testuser", "email": "test@example.com", "password": "password123"}
    create_response = client.post("/users/", json=user_data)
    assert create_response.status_code == 200
    user_id = create_response.json()["id"]

    # Retrieve the user
    response = client.get(f"/users/{user_id}")
    assert response.status_code == 200
    data = response.json()
    assert data["id"] == user_id
    assert data["username"] == user_data["username"]
    assert data["email"] == user_data["email"]

# Test for main.py::get_user_by_username
def test_get_user_by_username(client):
    """UNIVERSAL test for maximum coverage."""
    # Create a user
    user_data = {"username": "testuser", "email": "test@example.com", "password": "password123"}
    create_response = client.post("/users/", json=user_data)
    assert create_response.status_code == 200

    # Retrieve the user by username
    response = client.get(f"/users/username/{user_data['username']}")
    assert response.status_code == 200
    data = response.json()
    assert data["username"] == user_data["username"]
    assert data["email"] == user_data["email"]

    # Test for non-existent username
    response = client.get("/users/username/nonexistentuser")
    assert response.status_code == 404
    assert response.json()["detail"] == "User not found"